{
  "name": "HR-Pro: Sistem Kontrol & Data Pegawai",
  "description": "Aplikasi manajemen SDM canggih untuk mengelola data pegawai, kontrol kenaikan pangkat, kenaikan gaji berkala (KGB), dan monitoring pensiun dengan dukungan AI Gemini."
}

export enum Golongan {
  IA = 'I/a', IB = 'I/b', IC = 'I/c', ID = 'I/d',
  IIA = 'II/a', IIB = 'II/b', IIC = 'II/c', IID = 'II/d',
  IIIA = 'III/a', IIIB = 'III/b', IIIC = 'III/c', IIID = 'III/d',
  IVA = 'IV/a', IVB = 'IV/b', IVC = 'IV/c', IVD = 'IV/d', IVE = 'IV/e'
}

export interface Employee {
  id: string;
  nip: string;
  nama: string;
  jabatan: string;
  golongan: Golongan;
  tmtGolongan: string; // YYYY-MM-DD (Last Promotion)
  tmtKgb: string;      // YYYY-MM-DD (Last Salary Increase)
  tanggalLahir: string; // YYYY-MM-DD
  unitKerja: string;
  avatar?: string;
}

export interface ControlReport {
  title: string;
  count: number;
  employees: Employee[];
  type: 'PANGKAT' | 'KGB' | 'PENSIUN';
}

export type ViewType = 'DASHBOARD' | 'DATA_PEGAWAI' | 'KONTROL_PANGKAT' | 'KONTROL_KGB' | 'KONTROL_PENSIUN' | 'AI_REPORT';

import { GoogleGenAI } from "@google/genai";
import { Employee } from "../types";

export const getAIAnalysis = async (employees: Employee[]) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const prompt = `
      Anda adalah pakar HR Analytics. Berdasarkan data pegawai berikut, berikan analisis ringkas:
      1. Ringkasan jumlah pegawai dan profil golongan.
      2. Berikan saran strategis untuk perencanaan kenaikan pangkat dan pensiun (regenerasi).
      3. Identifikasi jika ada pegawai yang sudah mendekati masa pensiun (asumsi 58 tahun).

      Data Pegawai:
      ${JSON.stringify(employees.map(e => ({
        nama: e.nama,
        golongan: e.golongan,
        tmtGolongan: e.tmtGolongan,
        tanggalLahir: e.tanggalLahir
      })))}

      Gunakan Bahasa Indonesia yang formal dan berikan poin-poin penting.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return "Maaf, terjadi kesalahan saat melakukan analisis AI. Pastikan API key dikonfigurasi dengan benar.";
  }
};

import { Employee } from "../types";

// Standard Rules:
// - Promotion (Pangkat): Every 4 years from TMT Golongan
// - Periodic Salary (KGB): Every 2 years from TMT KGB
// - Retirement (Pensiun): Age 58

export const getNextPromotion = (tmt: string) => {
  const date = new Date(tmt);
  date.setFullYear(date.getFullYear() + 4);
  return date;
};

export const getNextKgb = (tmt: string) => {
  const date = new Date(tmt);
  date.setFullYear(date.getFullYear() + 2);
  return date;
};

export const getRetirementDate = (birthDate: string, age: number = 58) => {
  const date = new Date(birthDate);
  date.setFullYear(date.getFullYear() + age);
  // Usually retired on the 1st of the month following birth month
  date.setMonth(date.getMonth() + 1);
  date.setDate(1);
  return date;
};

export const isNear = (targetDate: Date, monthsThreshold: number = 12) => {
  const now = new Date();
  const threshold = new Date();
  threshold.setMonth(now.getMonth() + monthsThreshold);
  return targetDate <= threshold && targetDate >= now;
};

export const formatDate = (date: Date | string) => {
  const d = typeof date === 'string' ? new Date(date) : date;
  return d.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });
};

