export const extractEmployeeDataFromImage = async (base64Image: string): Promise<Partial<Employee> | null> => {
  try {
    const prompt = `
      Extract employee information from this document (Kenaikan Gaji Berkala / SK).
      Return ONLY a JSON object with the following fields:
      - nama: string
      - nip: string (digits only, no spaces)
      - jabatan: string
      - golongan: string (must be one of: I/a, I/b, I/c, I/d, II/a, II/b, II/c, II/d, III/a, III/b, III/c, III/d, IV/a, IV/b, IV/c, IV/d, IV/e)
      - tanggalLahir: string (format YYYY-MM-DD)
      - unitKerja: string
      - tmtKgb: string (The date the new salary starts, format YYYY-MM-DD)

      Example of mapping: 
      If document says "Penata Tk. I / III/d", golongan is "III/d".
      If document says "01 Maret 2026", format as "2026-03-01".
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { text: prompt },
        { inlineData: { mimeType: "image/jpeg", data: base64Image } }
      ],
      config: {
        responseMimeType: "application/json"
      }
    });

    const text = response.text;
    if (!text) return null;

    return JSON.parse(text) as Partial<Employee>;
  } catch (error) {
    console.error("AI Extraction Error:", error);
    return null;
  }
};

import React, { useState, useRef } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';

interface AddEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
}

const AddEmployeeModal: React.FC<AddEmployeeModalProps> = ({ isOpen, onClose, onSave }) => {
  const [activeTab, setActiveTab] = useState<'MANUAL' | 'SCAN'>('SCAN');
  const [isScanning, setIsScanning] = useState(false);
  const [formData, setFormData] = useState<Partial<Employee>>({
    nama: '',
    nip: '',
    jabatan: '',
    golongan: Golongan.IIIA,
    unitKerja: '',
    tanggalLahir: '',
    tmtGolongan: new Date().toISOString().split('T')[0],
    tmtKgb: new Date().toISOString().split('T')[0],
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isOpen) return null;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const extractedData = await extractEmployeeDataFromImage(base64String);

      if (extractedData) {
        setFormData(prev => ({ ...prev, ...extractedData }));
        setActiveTab('MANUAL'); // Switch to manual tab to let user verify
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newEmployee: Employee = {
      ...formData as Employee,
      id: Math.random().toString(36).substr(2, 9),
      avatar: `https://picsum.photos/seed/${formData.nama}/200`
    };
    onSave(newEmployee);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-indigo-50/50">
          <div>
            <h2 className="text-xl font-bold text-gray-900">Tambah Pegawai Baru</h2>
            <p className="text-sm text-gray-500">Lengkapi data pegawai secara manual atau menggunakan AI Scanner</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white rounded-full transition-colors text-gray-400 hover:text-gray-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-gray-100">
          <button 
            onClick={() => setActiveTab('SCAN')}
            className={`flex-1 py-3 text-sm font-semibold transition-all flex items-center justify-center space-x-2 ${activeTab === 'SCAN' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
            <span>Scan Dokumen (AI)</span>
          </button>
          <button 
            onClick={() => setActiveTab('MANUAL')}
            className={`flex-1 py-3 text-sm font-semibold transition-all flex items-center justify-center space-x-2 ${activeTab === 'MANUAL' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-indigo-50/30' : 'text-gray-500 hover:bg-gray-50'}`}
