        <div className="p-6 border-t border-gray-100 bg-gray-50 flex justify-end space-x-3">
          <button onClick={onClose} className="px-6 py-2 rounded-xl text-sm font-semibold text-gray-500 hover:bg-gray-200 transition-colors">Batal</button>
