              <div className="w-10 h-10 rounded-xl bg-slate-700 border border-slate-600 overflow-hidden">
                <img src="https://picsum.photos/seed/admin/200" alt="Admin" />
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-xs text-slate-500 font-bold uppercase tracking-tighter">Authorized Admin</p>
                <p className="text-sm font-bold truncate">Irnadi Kusuma</p>
              </div>
            </div>
            <button className="w-full py-2 bg-slate-700 hover:bg-slate-600 text-xs font-bold rounded-xl transition-colors">Keluar Sistem</button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Toast Notification */}
        {toast && (
          <div className="fixed top-24 right-8 z-50 animate-slideInRight">
