        {/* Header */}
        <header className="bg-white border-b border-gray-100 px-10 py-6 flex items-center justify-between sticky top-0 z-10 shadow-sm">
          <div>
            <h1 className="text-2xl font-black text-slate-900 tracking-tight">
              {NAV_ITEMS.find(n => n.id === currentView)?.label}
            </h1>
            <p className="text-xs text-slate-400 font-medium mt-0.5">Sistem Manajemen SDM Terintegrasi</p>
