                    <button onClick={() => setIsModalOpen(true)} className="flex items-center p-5 bg-indigo-600 rounded-3xl hover:bg-indigo-700 transition-all group shadow-lg shadow-indigo-600/20">
                      <div className="bg-white/20 p-3 rounded-2xl mr-4 group-hover:scale-110 transition-transform">
