                  <div className="flex items-center space-x-6">
                    <div className="p-5 bg-indigo-600 rounded-[2rem] text-white">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"/></svg>
                    </div>
                    <div>
                      <h2 className="text-3xl font-black text-slate-900 tracking-tight">AI Strategy Insight</h2>
                    </div>
                  </div>
                  <button 
                    onClick={handleGenerateAI}
                    disabled={isLoadingAi}
                    className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black text-xs uppercase tracking-widest shadow-xl disabled:opacity-50"
                  >
                    {isLoadingAi ? 'Menganalisis...' : 'Mulai Analisis AI'}
                  </button>
                </div>

                <div className="bg-gray-50/50 p-10 rounded-[2.5rem] border-2 border-dashed border-gray-100 min-h-[500px]">
                  {aiReport ? (
                    <div className="whitespace-pre-wrap text-slate-700 leading-relaxed font-medium text-lg">
                      {aiReport}
                    </div>
                  ) : (
                    <p className="text-center text-slate-300 py-20">Belum ada laporan.</p>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      <AddEmployeeModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSave={handleSaveEmployee} 
      />
    </div>
  );
};

