import React, { useState, useRef, useEffect } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
  onDelete?: (id: string) => void;
  initialData?: Employee | null;
}

const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, onDelete, initialData }) => {
  const [activeTab, setActiveTab] = useState<'MANUAL' | 'SCAN'>('SCAN');
  const [isScanning, setIsScanning] = useState(false);
  const [formData, setFormData] = useState<Partial<Employee>>({
    nama: '',
    nip: '',
    jabatan: '',
    golongan: Golongan.IIIA,
    unitKerja: '',
    tanggalLahir: '',
    tmtGolongan: new Date().toISOString().split('T')[0],
    tmtKgb: new Date().toISOString().split('T')[0],
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
      setActiveTab('MANUAL');
    } else {
      setFormData({
        nama: '',
        nip: '',
        jabatan: '',
        golongan: Golongan.IIIA,
        unitKerja: '',
        tanggalLahir: '',
        tmtGolongan: new Date().toISOString().split('T')[0],
        tmtKgb: new Date().toISOString().split('T')[0],
      });
      setActiveTab('SCAN');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const extractedData = await extractEmployeeDataFromImage(base64String);

      if (extractedData) {
        setFormData(prev => ({ ...prev, ...extractedData }));
        setActiveTab('MANUAL');
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const employee: Employee = {
      ...(formData as Employee),
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      avatar: initialData?.avatar || `https://picsum.photos/seed/${formData.nama}/200`
    };
    onSave(employee);
    onClose();
  };

  const handleDelete = () => {
    if (initialData && onDelete) {
      if (window.confirm(`Apakah Anda yakin ingin menghapus data pegawai ${initialData.nama}?`)) {
        onDelete(initialData.id);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh] border border-white">
        {/* Header */}
        <div className="p-8 border-b border-gray-100 flex justify-between items-center bg-indigo-50/30">
          <div>
            <h2 className="text-2xl font-black text-slate-900 tracking-tight">
              {initialData ? 'Detail & Edit Pegawai' : 'Tambah Pegawai Baru'}
            </h2>
            <p className="text-sm text-slate-500 font-medium">
              {initialData ? 'Kelola informasi profil dan riwayat pegawai' : 'Gunakan AI Scanner untuk input data otomatis'}
            </p>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-white rounded-2xl transition-all text-slate-400 hover:text-slate-600 shadow-sm border border-transparent hover:border-gray-100">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        {/* Tabs - Only show if adding new */}
        {!initialData && (
          <div className="flex border-b border-gray-100 bg-gray-50/50">
            <button 
              onClick={() => setActiveTab('SCAN')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center space-x-2 ${activeTab === 'SCAN' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-white' : 'text-slate-400 hover:bg-gray-100'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              <span>Scan Dokumen AI</span>
            </button>
            <button 
              onClick={() => setActiveTab('MANUAL')}
              className={`flex-1 py-4 text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center space-x-2 ${activeTab === 'MANUAL' ? 'text-indigo-600 border-b-2 border-indigo-600 bg-white' : 'text-slate-400 hover:bg-gray-100'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
              <span>Input Manual</span>
            </button>
          </div>
        )}

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-10">
          {activeTab === 'SCAN' && !initialData ? (
            <div className="flex flex-col items-center justify-center h-full py-8 text-center">
              <div 
                onClick={() => fileInputRef.current?.click()}
                className={`w-full max-w-md border-2 border-dashed rounded-[2.5rem] p-16 transition-all cursor-pointer flex flex-col items-center group shadow-sm ${isScanning ? 'border-indigo-300 bg-indigo-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-indigo-50/30'}`}
              >
                {isScanning ? (
                  <div className="flex flex-col items-center">
                    <svg className="animate-spin h-14 w-14 text-indigo-600 mb-6" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    <p className="text-indigo-600 font-black uppercase tracking-widest text-xs">AI Processing...</p>
                  </div>
                ) : (
                  <>
                    <div className="w-24 h-24 bg-indigo-100 text-indigo-600 rounded-3xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform shadow-lg shadow-indigo-100">
                      <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg>
                    </div>
                    <p className="font-black text-slate-800 text-xl tracking-tight">Upload Foto Dokumen</p>
                    <p className="text-sm text-slate-400 font-medium mt-2">AI akan mengisi form secara otomatis</p>
                    <div className="mt-8 px-10 py-3 bg-indigo-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-indigo-200 hover:bg-indigo-700 transition-all">Pilih File</div>
                  </>
                )}
                <input 
                  type="file" 
                  className="hidden" 
                  ref={fileInputRef} 
                  onChange={handleFileUpload} 
                  accept="image/*"
                />
              </div>
            </div>
          ) : (
            <form id="employee-form" onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-2 gap-8">
                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Nama Lengkap & Gelar</label>
                  <input required name="nama" value={formData.nama} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" placeholder="Nama Lengkap..." />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">NIP</label>
                  <input required name="nip" value={formData.nip} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" placeholder="198..." />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Golongan</label>
                  <select name="golongan" value={formData.golongan} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm">
                    {Object.values(Golongan).map(g => <option key={g} value={g}>{g}</option>)}
                  </select>
                </div>
                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Jabatan Struktural/Fungsional</label>
                  <input required name="jabatan" value={formData.jabatan} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" placeholder="Jabatan..." />
                </div>
                <div className="col-span-2">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Unit Kerja</label>
                  <input required name="unitKerja" value={formData.unitKerja} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" placeholder="Unit Kerja..." />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Tanggal Lahir</label>
                  <input required type="date" name="tanggalLahir" value={formData.tanggalLahir} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">TMT KGB Terakhir</label>
                  <input required type="date" name="tmtKgb" value={formData.tmtKgb} onChange={handleInputChange} className="w-full px-5 py-4 bg-gray-50 border border-gray-100 rounded-2xl font-bold text-slate-700 focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 outline-none transition-all shadow-sm" />
                </div>
              </div>
            </form>
          )}
        </div>

        {/* Footer */}
        <div className="p-8 border-t border-gray-100 bg-gray-50/50 flex justify-between items-center">
          <div>
            {initialData && (
              <button 
                type="button"
                onClick={handleDelete}
                className="px-6 py-3 rounded-2xl text-xs font-black uppercase tracking-widest text-rose-600 hover:bg-rose-50 transition-all border border-transparent hover:border-rose-100"
              >
                Hapus Pegawai
              </button>
            )}
          </div>
          <div className="flex space-x-4">
            <button onClick={onClose} className="px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest text-slate-500 hover:bg-gray-200 transition-all">Batal</button>
            <button 
              type="submit" 
              form="employee-form" 
              disabled={activeTab === 'SCAN' && !initialData}
              className={`px-10 py-3 rounded-2xl text-xs font-black uppercase tracking-widest text-white transition-all shadow-xl ${activeTab === 'SCAN' && !initialData ? 'bg-slate-300 cursor-not-allowed shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:-translate-y-1'}`}
            >
              {initialData ? 'Simpan Perubahan' : 'Simpan Pegawai'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeModal;

import React, { useState, useMemo } from 'react';
import { ViewType, Employee } from './types';
import { MOCK_EMPLOYEES, NAV_ITEMS } from './constants';
import StatCard from './components/StatCard';
import EmployeeTable from './components/EmployeeTable';
import EmployeeModal from './components/EmployeeModal';
import { getNextPromotion, getNextKgb, getRetirementDate, isNear, formatDate } from './utils/dateUtils';
import { getAIAnalysis } from './services/geminiService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('DASHBOARD');
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [aiReport, setAiReport] = useState<string>('');
  const [isLoadingAi, setIsLoadingAi] = useState<boolean>(false);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'info' | 'error' } | null>(null);

  // Filter States
  const [selectedMonth, setSelectedMonth] = useState<number | string>(''); // 0-11
  const [selectedYear, setSelectedYear] = useState<number | string>('');

  const currentYear = new Date().getFullYear();
  const yearOptions = Array.from({ length: 11 }, (_, i) => currentYear - 2 + i);
  const monthNames = ["Januari", "Februari", "Maret", "April", "Mei", "Juni", "Juli", "Agustus", "September", "Oktober", "November", "Desember"];

  // Logic for Pangkat Filtering
  const pangkatEligible = useMemo(() => {
    return employees.filter(e => {
      const nextDate = getNextPromotion(e.tmtGolongan);
      const matchesMonth = selectedMonth === '' || nextDate.getMonth() === Number(selectedMonth);
      const matchesYear = selectedYear === '' || nextDate.getFullYear() === Number(selectedYear);

      // If no filters, use the "isNear" logic (next 12 months)
      if (selectedMonth === '' && selectedYear === '') {
        return isNear(nextDate);
      }
      return matchesMonth && matchesYear;
    });
  }, [employees, selectedMonth, selectedYear]);

  // Logic for KGB Filtering
  const kgbEligible = useMemo(() => {
    return employees.filter(e => {
      const nextDate = getNextKgb(e.tmtKgb);
      const matchesMonth = selectedMonth === '' || nextDate.getMonth() === Number(selectedMonth);
      const matchesYear = selectedYear === '' || nextDate.getFullYear() === Number(selectedYear);

      if (selectedMonth === '' && selectedYear === '') {
        return isNear(nextDate);
      }
      return matchesMonth && matchesYear;
    });
  }, [employees, selectedMonth, selectedYear]);

  const retirementEligible = useMemo(() => 
    employees.filter(e => isNear(getRetirementDate(e.tanggalLahir))),
    [employees]
  );

  const filteredEmployees = useMemo(() => 
    employees.filter(e => 
      e.nama.toLowerCase().includes(searchQuery.toLowerCase()) || 
      e.nip.includes(searchQuery)
    ),
    [employees, searchQuery]
  );

  const stats = [
    { label: 'Total Pegawai', value: employees.length, color: 'bg-blue-100 text-blue-600', icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z"/></svg> },
    { label: 'Usul Pangkat (Filter)', value: pangkatEligible.length, color: 'bg-orange-100 text-orange-600', icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg> },
    { label: 'Usul KGB (Filter)', value: kgbEligible.length, color: 'bg-emerald-100 text-emerald-600', icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1"/></svg> },
    { label: 'Pensiun (12 Bln)', value: retirementEligible.length, color: 'bg-red-100 text-red-600', icon: <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 14l9-5-9-5-9 5 9 5z"/></svg> },
  ];

  const handleGenerateAI = async () => {
    setIsLoadingAi(true);
    const result = await getAIAnalysis(employees);
    setAiReport(result || 'Gagal memuat laporan AI.');
    setIsLoadingAi(false);
  };

  const handleSaveEmployee = (emp: Employee) => {
    if (selectedEmployee) {
      // Update
      setEmployees(prev => prev.map(e => e.id === emp.id ? emp : e));
      setToast({ message: `Data ${emp.nama} berhasil diperbarui!`, type: 'success' });
    } else {
      // Create
      setEmployees(prev => [emp, ...prev]);
      setToast({ message: `Pegawai ${emp.nama} berhasil ditambahkan!`, type: 'success' });
    }
    setTimeout(() => setToast(null), 4000);
    setSelectedEmployee(null);
  };

  const handleDeleteEmployee = (id: string) => {
    setEmployees(prev => prev.filter(e => e.id !== id));
    setToast({ message: `Data pegawai berhasil dihapus.`, type: 'info' });
    setTimeout(() => setToast(null), 4000);
    setSelectedEmployee(null);
  };

  const handleOpenDetail = (emp: Employee) => {
    setSelectedEmployee(emp);
    setIsModalOpen(true);
  };

  const resetFilters = () => {
    setSelectedMonth('');
    setSelectedYear('');
  };

  const chartData = useMemo(() => {
    const groups = employees.reduce((acc, curr) => {
      acc[curr.golongan] = (acc[curr.golongan] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    return Object.entries(groups).map(([name, value]) => ({ name, value }));
  }, [employees]);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

  const FilterBar = () => (
    <div className="bg-white p-8 rounded-[2.5rem] shadow-xl shadow-slate-200/40 border border-white flex flex-wrap items-end gap-8 mb-10">
      <div className="flex-1 min-w-[200px]">
        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Filter Bulan Pelaksanaan</label>
        <select 
          value={selectedMonth} 
          onChange={(e) => setSelectedMonth(e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-4 text-sm font-bold text-slate-700 outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 transition-all"
        >
          <option value="">Semua Bulan</option>
          {monthNames.map((m, i) => <option key={i} value={i}>{m}</option>)}
        </select>
      </div>
      <div className="flex-1 min-w-[200px]">
        <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Filter Tahun Pelaksanaan</label>
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 rounded-2xl px-5 py-4 text-sm font-bold text-slate-700 outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-300 transition-all"
        >
          <option value="">Semua Tahun</option>
          {yearOptions.map(y => <option key={y} value={y}>{y}</option>)}
        </select>
