                  </div>
                </div>
              )}
            </form>
          )}
        </div>

        {/* Footer */}
        <div className="p-10 border-t border-gray-100 bg-gray-50/50 flex justify-between items-center">
          <div>
            {initialData && (
              <button type="button" onClick={handleDelete} className="px-10 py-4 rounded-2xl text-xs font-black uppercase tracking-widest text-rose-600 hover:bg-rose-50 transition-all border-2 border-transparent hover:border-rose-100">Hapus Data Pegawai</button>
            )}
