          <div className="flex space-x-6">
            <button onClick={onClose} className="px-10 py-4 rounded-2xl text-sm font-black uppercase tracking-widest text-slate-500 hover:bg-gray-200 transition-all">Batal</button>
            <button type="submit" form="employee-form" className={`px-14 py-4 rounded-[1.5rem] text-sm font-black uppercase tracking-widest text-white transition-all shadow-2xl bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:-translate-y-1`}>
              {initialData ? 'Simpan Perubahan' : 'Finalisasi & Simpan'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

