import React, { useState, useRef, useEffect } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
  onDelete?: (id: string) => void;
  initialData?: Employee | null;
}

const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, onDelete, initialData }) => {
  const [activeTab, setActiveTab] = useState<'MANUAL' | 'SCAN' | 'SKP_LAMA' | 'SKP_BARU'>('SCAN');
  const [isScanning, setIsScanning] = useState(false);
  const [formData, setFormData] = useState<Partial<Employee>>({
    nama: '',
    nip: '',
    jabatan: '',
    golongan: Golongan.IIIA,
    unitKerja: '',
    tanggalLahir: '',
    tmtGolongan: new Date().toISOString().split('T')[0],
    tmtKgb: new Date().toISOString().split('T')[0],
    gajiPokokLama: '',
    nomorSkpTerakhir: '',
    tglSkpTerakhir: '',
    tglMulaiGajiLama: '',
    masaKerjaGolonganLama: '',
    gajiPokokBaru: '',
    masaKerjaBaru: '',
    golonganBaru: '',
    keterangan: '',
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
      setFormData({ ...formData, ...initialData });
      setActiveTab('MANUAL');
    } else {
      setFormData({
        nama: '',
        nip: '',
        jabatan: '',
        golongan: Golongan.IIIA,
        unitKerja: '',
        tanggalLahir: '',
        tmtGolongan: new Date().toISOString().split('T')[0],
        tmtKgb: new Date().toISOString().split('T')[0],
        gajiPokokLama: '',
        nomorSkpTerakhir: '',
        tglSkpTerakhir: '',
        tglMulaiGajiLama: '',
        masaKerjaGolonganLama: '',
        gajiPokokBaru: '',
        masaKerjaBaru: '',
        golonganBaru: '',
        keterangan: '',
      });
      setActiveTab('SCAN');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const extractedData = await extractEmployeeDataFromImage(base64String);

      if (extractedData) {
        setFormData(prev => ({ ...prev, ...extractedData }));
        setActiveTab('MANUAL');
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const employee: Employee = {
      ...(formData as Employee),
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      avatar: initialData?.avatar || `https://picsum.photos/seed/${formData.nama}/200`
    };
    onSave(employee);
    onClose();
  };

  const handleDelete = () => {
    if (initialData && onDelete) {
      if (window.confirm(`Apakah Anda yakin ingin menghapus seluruh data pegawai "${initialData.nama}" secara permanen? Tindakan ini tidak dapat dibatalkan.`)) {
        onDelete(initialData.id);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
      <div className="bg-white rounded-[4rem] shadow-2xl w-full max-w-7xl overflow-hidden flex flex-col max-h-[94vh] border border-white relative">
        {/* Decorative background element */}
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-50 rounded-full blur-[100px] -mr-48 -mt-48 opacity-50"></div>

        {/* Header Section */}
        <div className="p-12 border-b border-slate-100 flex justify-between items-start bg-white relative z-10">
          <div className="flex items-center space-x-8">
             <div className="w-24 h-24 rounded-[2rem] bg-indigo-50 flex items-center justify-center text-indigo-600 shadow-inner overflow-hidden border-4 border-white shadow-xl">
               {initialData?.avatar ? (
                 <img src={initialData.avatar} className="w-full h-full object-cover" />
               ) : (
                 <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>
               )}
             </div>
             <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight leading-tight">
                  {initialData ? 'Profil & Manajemen Pegawai' : 'Tambah Pegawai Baru'}
                </h2>
                <p className="text-lg text-slate-400 font-bold mt-2 max-w-2xl">
                  {initialData ? `Kelola informasi detail ${initialData.nama}, termasuk riwayat pangkat, KGB lama, dan penetapan baru.` : 'Unggah dokumen SK melalui AI Scanner atau masukkan data secara manual untuk pendaftaran pegawai baru.'}
                </p>
             </div>
          </div>
          <button 
            onClick={onClose} 
            className="group p-5 bg-slate-50 hover:bg-rose-50 rounded-[1.5rem] transition-all duration-300 text-slate-300 hover:text-rose-500 shadow-sm border border-transparent hover:border-rose-100"
          >
            <svg className="w-10 h-10 group-hover:rotate-90 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        {/* Improved Navigation Tabs */}
        <div className="flex px-12 border-b border-slate-50 bg-white relative z-10 overflow-x-auto scrollbar-hide">
          {!initialData && (
            <button 
              onClick={() => setActiveTab('SCAN')} 
              className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'SCAN' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              <span>1. Scan AI</span>
            </button>
          )}
          <button 
            onClick={() => setActiveTab('MANUAL')} 
