export default EmployeeModal;

import React, { useState, useRef, useEffect } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
  onDelete?: (id: string) => void;
  initialData?: Employee | null;
}

const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, onDelete, initialData }) => {
  // Urutan Tab: Data Dasar -> SKP Lama -> SKP Baru -> (Scan AI jika tambah baru)
  const [activeTab, setActiveTab] = useState<'MANUAL' | 'SKP_LAMA' | 'SKP_BARU' | 'SCAN'>('MANUAL');
  const [isScanning, setIsScanning] = useState(false);
  const [formData, setFormData] = useState<Partial<Employee>>({
    nama: '',
    nip: '',
    jabatan: '',
    golongan: Golongan.IIIA,
    unitKerja: '',
    tanggalLahir: '',
    tmtGolongan: new Date().toISOString().split('T')[0],
    tmtKgb: new Date().toISOString().split('T')[0],
    gajiPokokLama: '',
    nomorSkpTerakhir: '',
    tglSkpTerakhir: '',
    tglMulaiGajiLama: '',
    masaKerjaGolonganLama: '',
    gajiPokokBaru: '',
    masaKerjaBaru: '',
    golonganBaru: '',
    keterangan: '',
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
      setFormData({ ...formData, ...initialData });
      setActiveTab('MANUAL');
    } else {
      setFormData({
        nama: '',
        nip: '',
        jabatan: '',
        golongan: Golongan.IIIA,
        unitKerja: '',
        tanggalLahir: '',
        tmtGolongan: new Date().toISOString().split('T')[0],
        tmtKgb: new Date().toISOString().split('T')[0],
        gajiPokokLama: '',
        nomorSkpTerakhir: '',
        tglSkpTerakhir: '',
        tglMulaiGajiLama: '',
        masaKerjaGolonganLama: '',
        gajiPokokBaru: '',
        masaKerjaBaru: '',
        golonganBaru: '',
        keterangan: '',
      });
      setActiveTab('MANUAL'); // Default ke Data Dasar untuk input manual
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const extractedData = await extractEmployeeDataFromImage(base64String);

      if (extractedData) {
        setFormData(prev => ({ ...prev, ...extractedData }));
        setActiveTab('MANUAL');
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const employee: Employee = {
      ...(formData as Employee),
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      avatar: initialData?.avatar || `https://picsum.photos/seed/${formData.nama}/200`
    };
    onSave(employee);
    onClose();
  };

  const handleDelete = () => {
    if (initialData && onDelete) {
      if (window.confirm(`PERINGATAN: Apakah Anda yakin ingin menghapus seluruh data pegawai "${initialData.nama}" secara permanen? Tindakan ini akan menghapus seluruh riwayat pangkat dan KGB.`)) {
        onDelete(initialData.id);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
      <div className="bg-white rounded-[4rem] shadow-2xl w-full max-w-7xl overflow-hidden flex flex-col max-h-[94vh] border border-white relative">
