          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
            <span>3. SKP Baru</span>
          </button>
          {!initialData && (
            <button 
              onClick={() => setActiveTab('SCAN')} 
              className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'SCAN' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              <span>Scan AI Otomatis</span>
            </button>
          )}
        </div>

        {/* Form Content */}
        <div className="flex-1 overflow-y-auto p-16 bg-slate-50/50">
          {activeTab === 'SCAN' && !initialData ? (
             <div className="flex flex-col items-center justify-center h-full text-center">
