export default EmployeeModal;

export enum Golongan {
  IA = 'I/a', IB = 'I/b', IC = 'I/c', ID = 'I/d',
  IIA = 'II/a', IIB = 'II/b', IIC = 'II/c', IID = 'II/d',
  IIIA = 'III/a', IIIB = 'III/b', IIIC = 'III/c', IIID = 'III/d',
  IVA = 'IV/a', IVB = 'IV/b', IVC = 'IV/c', IVD = 'IV/d', IVE = 'IV/e'
}

export interface Employee {
  id: string;
  nip: string;
  nama: string;
  jabatan: string;
  golongan: Golongan;
  tmtGolongan: string; // YYYY-MM-DD (Last Promotion)
  tmtKgb: string;      // YYYY-MM-DD (Last Salary Increase)
  tanggalLahir: string; // YYYY-MM-DD
  tempatLahir?: string;
  noHp?: string;
  unitKerja: string;
  avatar?: string;

  // SKP Lama (Existing Data from Document)
  gajiPokokLama?: string;
  nomorSkpTerakhir?: string;
  tglSkpTerakhir?: string;
  tglMulaiGajiLama?: string;
  masaKerjaGolonganLama?: string;

  // SKP Baru (New Data from Document)
  gajiPokokBaru?: string;
  masaKerjaBaru?: string;
  golonganBaru?: string;
  keterangan?: string;
}

export interface ControlReport {
  title: string;
  count: number;
  employees: Employee[];
  type: 'PANGKAT' | 'KGB' | 'PENSIUN';
}

export type ViewType = 'DASHBOARD' | 'DATA_PEGAWAI' | 'KONTROL_PANGKAT' | 'KONTROL_KGB' | 'KONTROL_PENSIUN' | 'AI_REPORT';

import React, { useState, useRef, useEffect } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
  onDelete?: (id: string) => void;
  initialData?: Employee | null;
}

const EmployeeModal: React.FC<EmployeeModalProps> = ({ isOpen, onClose, onSave, onDelete, initialData }) => {
  const [activeTab, setActiveTab] = useState<'DATA_PEGAWAI' | 'SKP_LAMA' | 'SKP_BARU' | 'SCAN'>('DATA_PEGAWAI');
  const [isScanning, setIsScanning] = useState(false);
  const [formData, setFormData] = useState<Partial<Employee>>({
    nama: '',
    nip: '',
    jabatan: '',
    golongan: Golongan.IIIA,
    unitKerja: '',
    tanggalLahir: '',
    tempatLahir: '',
    noHp: '',
    tmtGolongan: new Date().toISOString().split('T')[0],
    tmtKgb: new Date().toISOString().split('T')[0],
    gajiPokokLama: '',
    nomorSkpTerakhir: '',
    tglSkpTerakhir: '',
    tglMulaiGajiLama: '',
    masaKerjaGolonganLama: '',
    gajiPokokBaru: '',
    masaKerjaBaru: '',
    golonganBaru: '',
    keterangan: '',
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialData) {
      setFormData({ ...formData, ...initialData });
      setActiveTab('DATA_PEGAWAI');
    } else {
      setFormData({
        nama: '',
        nip: '',
        jabatan: '',
        golongan: Golongan.IIIA,
        unitKerja: '',
        tanggalLahir: '',
        tempatLahir: '',
        noHp: '',
        tmtGolongan: new Date().toISOString().split('T')[0],
        tmtKgb: new Date().toISOString().split('T')[0],
        gajiPokokLama: '',
        nomorSkpTerakhir: '',
        tglSkpTerakhir: '',
        tglMulaiGajiLama: '',
        masaKerjaGolonganLama: '',
        gajiPokokBaru: '',
        masaKerjaBaru: '',
        golonganBaru: '',
        keterangan: '',
      });
      setActiveTab('DATA_PEGAWAI');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = (reader.result as string).split(',')[1];
      const extractedData = await extractEmployeeDataFromImage(base64String);

      if (extractedData) {
        setFormData(prev => ({ ...prev, ...extractedData }));
        setActiveTab('DATA_PEGAWAI');
      }
      setIsScanning(false);
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const employee: Employee = {
      ...(formData as Employee),
      id: initialData?.id || Math.random().toString(36).substr(2, 9),
      unitKerja: formData.unitKerja || 'Dinas Pusat',
      avatar: initialData?.avatar || `https://picsum.photos/seed/${formData.nama}/200`
    };
    onSave(employee);
    onClose();
  };

  const handleDelete = () => {
    if (initialData && onDelete) {
      if (window.confirm(`PERINGATAN: Apakah Anda yakin ingin menghapus data pegawai "${initialData.nama}"? Seluruh data riwayat gaji akan ikut terhapus.`)) {
        onDelete(initialData.id);
        onClose();
      }
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-md animate-fadeIn">
      <div className="bg-white rounded-[4rem] shadow-2xl w-full max-w-7xl overflow-hidden flex flex-col max-h-[94vh] border border-white relative">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-50 rounded-full blur-[100px] -mr-48 -mt-48 opacity-50"></div>

        {/* Header */}
        <div className="p-12 border-b border-slate-100 flex justify-between items-start bg-white relative z-10">
          <div className="flex items-center space-x-8">
             <div className="w-24 h-24 rounded-[2rem] bg-indigo-50 flex items-center justify-center text-indigo-600 shadow-inner overflow-hidden border-4 border-white shadow-xl">
               {initialData?.avatar ? (
                 <img src={initialData.avatar} className="w-full h-full object-cover" alt="Profile" />
               ) : (
                 <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>
               )}
             </div>
             <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight leading-tight">
                  {initialData ? 'Detail Informasi Pegawai' : 'Pendaftaran Pegawai Baru'}
                </h2>
                <p className="text-lg text-slate-400 font-bold mt-2 max-w-2xl">
                  {initialData ? `Kelola data diri, histori SKP lama, dan penetapan gaji baru untuk ${initialData.nama}.` : 'Lengkapi data identitas, rincian SKP lama, dan penetapan SKP baru secara manual atau scan dokumen.'}
                </p>
             </div>
          </div>
          <button onClick={onClose} className="group p-5 bg-slate-50 hover:bg-rose-50 rounded-[1.5rem] transition-all duration-300 text-slate-300 hover:text-rose-500 shadow-sm border border-transparent hover:border-rose-100">
            <svg className="w-10 h-10 group-hover:rotate-90 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        {/* Tab Menu */}
        <div className="flex px-12 border-b border-slate-50 bg-white relative z-10 overflow-x-auto scrollbar-hide">
          <button 
            onClick={() => setActiveTab('DATA_PEGAWAI')} 
            className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'DATA_PEGAWAI' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>
            <span>1. Data Pegawai</span>
          </button>
          <button 
            onClick={() => setActiveTab('SKP_LAMA')} 
            className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'SKP_LAMA' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
            <span>2. SKP Lama</span>
          </button>
          <button 
            onClick={() => setActiveTab('SKP_BARU')} 
            className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'SKP_BARU' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
            <span>3. SKP Baru</span>
          </button>
          {!initialData && (
            <button 
              onClick={() => setActiveTab('SCAN')} 
              className={`flex items-center space-x-3 py-8 px-10 text-sm font-black uppercase tracking-[0.2em] transition-all border-b-4 ${activeTab === 'SCAN' ? 'text-indigo-600 border-indigo-600' : 'text-slate-300 border-transparent hover:text-slate-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"/><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"/></svg>
              <span>Scan AI Otomatis</span>
            </button>
          )}
        </div>

        {/* Form Content */}
        <div className="flex-1 overflow-y-auto p-16 bg-slate-50/50">
          {activeTab === 'SCAN' && !initialData ? (
             <div className="flex flex-col items-center justify-center h-full text-center">
                <div onClick={() => fileInputRef.current?.click()} className="w-full max-w-4xl border-4 border-dashed rounded-[4rem] p-32 transition-all cursor-pointer flex flex-col items-center group shadow-2xl bg-white border-slate-100 hover:border-indigo-500">
                  {isScanning ? (
                    <div className="flex flex-col items-center">
                      <svg className="animate-spin h-32 w-32 text-indigo-600 mb-10" fill="none" viewBox="0 0 24 24"><circle className="opacity-10" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-90" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                      <p className="text-indigo-600 font-black uppercase tracking-[0.4em] text-lg">Gemini AI Sedang Mengekstrak Data...</p>
                    </div>
                  ) : (
                    <>
                      <div className="w-48 h-48 bg-indigo-50 text-indigo-600 rounded-[3.5rem] flex items-center justify-center mb-10 group-hover:scale-110 transition-transform duration-500 shadow-xl">
                        <svg className="w-24 h-24" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                      </div>
                      <p className="font-black text-slate-900 text-4xl tracking-tight leading-tight">Seret SK KGB ke Sini</p>
                      <p className="text-xl text-slate-400 font-bold mt-6">Atau klik untuk memilih file dari perangkat Anda</p>
                    </>
                  )}
                  <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileUpload} accept="image/*" />
                </div>
             </div>
          ) : (
            <form id="employee-form" onSubmit={handleSubmit} className="space-y-20 max-w-5xl mx-auto">
              {activeTab === 'DATA_PEGAWAI' && (
                <div className="grid grid-cols-2 gap-16 animate-fadeIn">
                  <div className="col-span-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Nama Pegawai</label>
                    <input required name="nama" value={formData.nama} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-2xl text-slate-800 outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="Contoh: NOVI HARYANTO, S. Adm" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">NIP</label>
                    <input required name="nip" value={formData.nip} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none" placeholder="19XXXXXXXXXXXXXXX" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Gol/Ruang</label>
                    <select name="golongan" value={formData.golongan} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none appearance-none">
                      {Object.values(Golongan).map(g => <option key={g} value={g}>{g}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Jabatan</label>
                    <input required name="jabatan" value={formData.jabatan} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none" placeholder="Contoh: Kepala Sub Bagian Umum" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">No. HP</label>
                    <input name="noHp" value={formData.noHp || ''} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none" placeholder="08XXXXXXXXXX" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Tempat Lahir</label>
                    <input name="tempatLahir" value={formData.tempatLahir || ''} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none" placeholder="Contoh: Jakarta" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Tgl. Lahir</label>
                    <input required type="date" name="tanggalLahir" value={formData.tanggalLahir} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none" />
                  </div>
                </div>
              )}

              {activeTab === 'SKP_LAMA' && (
                <div className="grid grid-cols-2 gap-16 animate-fadeIn">
                  <div className="col-span-2 bg-indigo-50/50 p-12 rounded-[3.5rem] border-2 border-indigo-100 mb-6 flex items-center">
                    <div className="bg-indigo-600 p-5 rounded-[1.5rem] text-white mr-8 shadow-xl shadow-indigo-200">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                    </div>
                    <div>
                      <p className="text-xl font-black text-indigo-900 uppercase tracking-widest leading-none">Informasi SKP Terakhir (Lama)</p>
                      <p className="text-base text-indigo-500 font-bold mt-2 opacity-80 italic">Data acuan berdasarkan Surat Keputusan penetapan gaji berkala yang lalu</p>
                    </div>
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Gaji Pokok Lama</label>
                    <input name="gajiPokokLama" value={formData.gajiPokokLama} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" placeholder="Contoh: Rp. 4.508.600,-" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Nomer SKP Terakhir</label>
                    <input name="nomorSkpTerakhir" value={formData.nomorSkpTerakhir} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" placeholder="822.3/..." />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Tgl. SKP Terakhir</label>
                    <input type="date" name="tglSkpTerakhir" value={formData.tglSkpTerakhir} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Tgl. Mulai Gaji Pokok Lama</label>
                    <input type="date" name="tglMulaiGajiLama" value={formData.tglMulaiGajiLama} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" />
                  </div>
                  <div className="col-span-2">
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Masa Kerja Golongan</label>
                    <input name="masaKerjaGolonganLama" value={formData.masaKerjaGolonganLama} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" placeholder="Contoh: 28 Tahun 00 Bulan" />
                  </div>
                </div>
              )}

              {activeTab === 'SKP_BARU' && (
                <div className="grid grid-cols-2 gap-16 animate-fadeIn">
                  <div className="col-span-2 bg-emerald-50/50 p-12 rounded-[3.5rem] border-2 border-emerald-100 mb-6 flex items-center">
                    <div className="bg-emerald-600 p-5 rounded-[1.5rem] text-white mr-8 shadow-xl shadow-emerald-200">
                      <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                    </div>
                    <div>
                      <p className="text-xl font-black text-emerald-900 uppercase tracking-widest leading-none">Penetapan Kenaikan Gaji Berkala (Baru)</p>
