                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Gaji Pokok Baru</label>
                    <input name="gajiPokokBaru" value={formData.gajiPokokBaru} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-emerald-100 rounded-[2.5rem] font-black text-3xl text-emerald-700 focus:ring-4 focus:ring-emerald-500/10 outline-none shadow-md" placeholder="Contoh: Rp. 5.022.500,-" />
