                  </div>
                  <div>
                    <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-5 ml-1">Golongan/Ruang</label>
                    <input name="golonganBaru" value={formData.golonganBaru} onChange={handleInputChange} className="w-full px-10 py-7 bg-white border border-slate-200 rounded-[2.5rem] font-black text-xl text-slate-800 outline-none shadow-sm" placeholder="Contoh: III/d" />
