                </div>
              )}
            </form>
          )}
        </div>

        {/* Footer Area */}
        <div className="p-12 border-t border-slate-100 bg-white relative z-10 flex justify-between items-center">
          <div>
            {initialData && (
              <button 
                type="button" 
                onClick={handleDelete} 
                className="group px-12 py-5 rounded-[2rem] text-sm font-black uppercase tracking-widest text-rose-500 hover:bg-rose-500 hover:text-white transition-all duration-300 border-2 border-rose-100 hover:border-rose-500 flex items-center space-x-4 shadow-sm"
