                <svg className="w-5 h-5 group-hover:animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                <span>Hapus Pegawai</span>
              </button>
            )}
          </div>
          <div className="flex space-x-8">
            <button 
              onClick={onClose} 
              className="px-14 py-5 rounded-[2rem] text-sm font-black uppercase tracking-widest text-slate-500 hover:bg-slate-100 transition-all duration-300"
            >
              Batal
            </button>
            <button 
              type="submit" 
