                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">NIP</label>
                  <input required name="nip" value={formData.nip} onChange={handleInputChange} className="w-full px-8 py-5 bg-white border border-slate-200 rounded-3xl font-bold text-lg text-slate-800 outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="19XXXXXXXXXXXXXXX" />
