      const confirmation = window.prompt('Ketik "HAPUS" untuk mengonfirmasi penghapusan seluruh database:');
      if (confirmation === 'HAPUS') {
        setEmployees([]);
        setToast({ message: 'Seluruh database pegawai telah dikosongkan.', type: 'error' });
