            >
              <div className={`${currentView === item.id ? 'text-white' : 'text-slate-500 group-hover:text-indigo-400'}`}>
                {item.icon}
              </div>
              <span className="font-bold text-sm tracking-wide">{item.label}</span>
            </button>
          ))}
        </nav>
        <div className="p-6">
          <div className="bg-slate-800/50 backdrop-blur-sm rounded-3xl p-5 border border-slate-700/50">
            <div className="flex items-center space-x-3 mb-3">
              <div className="w-10 h-10 rounded-xl bg-slate-700 border border-slate-600 overflow-hidden">
                <img src="https://picsum.photos/seed/admin/200" alt="Admin" />
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-xs text-slate-500 font-bold uppercase tracking-tighter">Authorized Admin</p>
                <p className="text-sm font-bold truncate">Irnadi Kusuma</p>
              </div>
            </div>
            <button className="w-full py-2 bg-slate-700 hover:bg-slate-600 text-[10px] font-black uppercase tracking-widest rounded-xl transition-colors">Keluar Sistem</button>
          </div>
