        {/* Close Button */}
        <button 
          onClick={() => setShowPreview(false)}
          className="absolute top-4 right-4 p-2 bg-rose-50 text-rose-500 rounded-full hover:bg-rose-100 transition-colors no-print"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
        </button>

        {/* Kop Surat Sesuai NTB */}
        <div className="flex items-center border-b-[3px] border-black pb-4 mb-6 relative">
