             <img 
               src="https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/Coat_of_arms_of_West_Nusa_Tenggara.static.png/500px-Coat_of_arms_of_West_Nusa_Tenggara.static.png" 
               alt="Logo NTB" 
               className="h-24 w-auto object-contain"
