                    <button onClick={() => setCurrentView('KONTROL_KGB')} className="flex items-center p-6 bg-white border-2 border-slate-50 rounded-[2rem] hover:border-indigo-100 hover:bg-indigo-50/30 transition-all group shadow-sm">
