            </button>
          ))}
        </nav>
        <div className="p-6 space-y-4">
          <div className={`rounded-3xl p-5 border text-center transition-all ${isSupabaseConfigured ? 'bg-emerald-500/10 border-emerald-500/20' : 'bg-slate-800/50 border-slate-700/50'}`}>
