import { useState, useEffect, useRef } from 'react';
import { supabase } from '../supabaseClient';
import { useToast } from '../components/ToastContext';
import EmployeeModal from '../components/EmployeeModal';
import { NAV_ITEMS } from '../components/Sidebar';

import { useWindowSize } from '../hooks/useWindowSize';
import { AiOutlineLogout } from 'react-icons/ai';

import { FaUser } from 'react-icons/fa';
import { HiOutlineUserAdd } from 'react-icons/hi';
import { MdEdit } from 'react-icons/md';
import { RiDeleteBinLine } from 'react-icons/ri';
import { AiOutlineReload } from 'react-icons/ai';

import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

function App() {
  const [employees, setEmployees] = useState([]);
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [currentView, setCurrentView] = useState('data-pegawai');
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [searchTerm, setSearchTerm] = useState('');
  const [filteredEmployees, setFilteredEmployees] = useState([]);
  const [dataForChart, setDataForChart] = useState([]); // State for chart data
  const toast = useToast();
  const [isDatabaseConnected, setIsDatabaseConnected] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [user, setUser] = useState(null);
  const isMounted = useRef(false);

  const windowSize = useWindowSize();
  const [isMobile, setIsMobile] = useState(windowSize.width < 768);

  const fetchData = async () => {
    setIsLoadingData(true);
    try {
      const { data, error } = await supabase
        .from('pegawai')
        .select('*');
      if (error) {
        console.error('Error fetching data:', error);
        toast.error(`Gagal memuat data pegawai: ${error.message}`);
      } else {
        setEmployees(data);
        setFilteredEmployees(data);
        setIsDatabaseConnected(true);
        generateChartData(data); // Generate chart data after fetching
      }
    } catch (error) {
      console.error('Unexpected error:', error);
      toast.error(`Terjadi kesalahan tak terduga: ${error.message}`);
    } finally {
      setIsLoadingData(false);
    }
  };

  useEffect(() => {
    if (windowSize.width < 768) {
      setIsMobile(true);
    } else {
      setIsMobile(false);
    }
