              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
              <span>{initialData ? 'Update Data' : 'Simpan Pegawai'}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default EmployeeModal;

import React, { useState, useRef, useEffect } from 'react';
import { Employee, Golongan } from '../types';
import { extractEmployeeDataFromImage } from '../services/geminiService';
import { formatDate } from '../utils/dateUtils';
import { formatRupiah } from '../utils/numberUtils';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (employee: Employee) => void;
  onDelete?: (id: string) => void;
  initialData?: Employee | null;
}

const LetterPreview: React.FC<{ formData: Partial<Employee>, setShowPreview: (show: boolean) => void }> = ({ formData, setShowPreview }) => {
  const handlePrint = () => {
    window.print();
  };

  // Daftar URL Logo NTB dari berbagai sumber untuk redundansi
  const logoSources = [
    "https://upload.wikimedia.org/wikipedia/commons/thumb/0/07/Coat_of_arms_of_West_Nusa_Tenggara.png/240px-Coat_of_arms_of_West_Nusa_Tenggara.png",
    "https://ntbprov.go.id/uploads/logo/logo_ntb.png",
