          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-10 bg-slate-50/30">
          <form id="employee-form" onSubmit={handleSubmit} className="space-y-8 max-w-3xl mx-auto">
            {activeTab === 'DATA' && (
              <div className="grid grid-cols-2 gap-6 animate-fadeIn">
