import { createClient } from '@supabase/supabase-js';

const getEnvValue = (keyName: string): string | undefined => {
  if (typeof window === 'undefined') return undefined;

  const searchKeys = [
    keyName.toUpperCase(),
    `VITE_${keyName.toUpperCase()}`,
    `NEXT_PUBLIC_${keyName.toUpperCase()}`
  ];

  for (const key of searchKeys) {
    try {
      // Cek import.meta.env
      const metaEnv = (import.meta as any).env;
      if (metaEnv && metaEnv[key]) return metaEnv[key];
    } catch (e) {}

    try {
      // Cek process.env
      if (typeof process !== 'undefined' && process.env && process.env[key]) {
        return process.env[key];
      }
    } catch (e) {}
  }

  return undefined;
};

const supabaseUrl = getEnvValue('SUPABASE_URL');
const supabaseAnonKey = getEnvValue('SUPABASE_ANON_KEY');

// Fungsi untuk mengecek apakah key adalah placeholder atau valid
const isValidConfig = (url?: string, key?: string) => {
  if (!url || !key) return false;
  const isPlaceholder = 
    url.includes('your-project') || 
    url.includes('YOUR_') || 
    key.includes('your-anon-key') || 
    key.includes('YOUR_');

  return !isPlaceholder && url.startsWith('https://');
};

export const isSupabaseConfigured = isValidConfig(supabaseUrl, supabaseAnonKey);

export const supabase = isSupabaseConfigured 
  ? createClient(supabaseUrl!, supabaseAnonKey!) 
  : null;

import { GoogleGenAI } from "@google/genai";
import { Employee } from "../types";

export const getAIAnalysis = async (employees: Employee[]) => {
  try {
    // Selalu inisialisasi baru dengan process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
    const prompt = `
      Anda adalah pakar HR Analytics. Berdasarkan data pegawai berikut, berikan analisis ringkas:
      1. Ringkasan jumlah pegawai dan profil golongan.
      2. Berikan saran strategis untuk perencanaan kenaikan pangkat dan pensiun (regenerasi).
      3. Identifikasi jika ada pegawai yang sudah mendekati masa pensiun (asumsi 58 tahun).

      Data Pegawai:
      ${JSON.stringify(employees.map(e => ({
        nama: e.nama,
        golongan: e.golongan,
        tmtGolongan: e.tmtGolongan,
        tanggalLahir: e.tanggalLahir
      })))}

      Gunakan Bahasa Indonesia yang formal dan berikan poin-poin penting.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return "Gagal melakukan analisis AI. Pastikan API Key Gemini sudah terkonfigurasi di environment variable.";
  }
};

export const extractEmployeeDataFromImage = async (base64Image: string): Promise<Partial<Employee> | null> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });
    const prompt = `
      Extract employee information from this document. 
      Fields needed: nama, nip, golongan, jabatan, tmtGolongan, tmtKgb, tanggalLahir.
      Return ONLY a JSON object.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { text: prompt },
        { inlineData: { mimeType: "image/jpeg", data: base64Image } }
      ],
      config: {
        responseMimeType: "application/json"
      }
    });

    const text = response.text;
    if (!text) return null;

    return JSON.parse(text) as Partial<Employee>;
  } catch (error) {
    console.error("AI Extraction Error:", error);
    return null;
  }
};

